+const FRONTMATTER = `---
+name: tenzir
+description: >
+  The complete Tenzir documentation. Covers deployment, configuration,
+  the Tenzir Query Language (TQL), operators, functions, formats,
+  connectors, integrations, and the Tenzir Platform.
